import { Link } from 'react-router-dom'
import React from 'react'
import { useTranslation } from 'react-i18next'

import './Header.css'
import Logo from '../icons/logo.svg'

const HeaderComponent = () => {
    const { t, i18n } = useTranslation()

    const handleLanguageChange = () => {
        const nextLanguage = i18n.resolvedLanguage === 'ua' ? 'en' : 'ua'
        i18n.changeLanguage(nextLanguage)
    }

    return (
        <header className="page-header">
            <div className="container page-header-wrapper">
                <nav className="site-navigation">
                    <ul className="reset-list">
                        <li>
                            <Link to="/">{t('header.navigation.aboutUs')}</Link>
                        </li>
                        <li>
                            <Link to="/become-pet-parent">{t('header.navigation.becomePetParent')}</Link>
                        </li>
                        <li>
                            <Link to="/results">{t('header.navigation.results')}</Link>
                        </li>
                    </ul>
                </nav>

                <Link className="page-header-logo-wrapper" to="/">
                    <img src={Logo} width="182" height="35" alt="ЩасСпасу – притулок і допомога для тварин" />
                </Link>

                <div className="page-header-action">
                    <button className="reset-button button button-support" type="button" disabled aria-disabled="true">
                        {t('header.support')}
                    </button>

                    <button className="reset-button button button-language-switch" type="button" onClick={handleLanguageChange}>
                        {i18n.resolvedLanguage === 'en' ? 'UA' : 'EN'}
                    </button>
                </div>
            </div>
        </header>
    )
}

export default HeaderComponent
